"use strict";const t=require("../util/http.js");exports.getUserInfoAPI=()=>t.http({method:"GET",url:"/wxuser/getUserInfo"}),exports.openidLoginAPI=e=>t.http({method:"POST",url:"/wxuser/openidLogin",data:{openid:e}}),exports.setUserAudioUrlAPI=e=>t.http({method:"POST",url:"/wxuser/setUserAudioUrl",data:{audioUrl:e}}),exports.updateUserInfoAPI=e=>t.http({method:"POST",url:"/wxuser/updateUserInfo",data:{nickname:e.nickname,avatar:e.avatar}}),exports.wxLoginAPI=e=>t.http({method:"POST",url:"/user/login",data:e}),exports.wxQuickLoginAPI=e=>t.http({method:"POST",url:"/wxuser/wxQuickLogin",data:{code:e}});
